CREATE OR REPLACE VIEW as ignados_por_tareaASSELECT TOP 100 Orden_fabricacion.nro_plan AS Lote, Tareas_cabecera.nro_orden_fabricacion, Tareas_cabecera.nro_tarea, Orden_fabricacion.cod_articulo, Orden_fab ORDER BY as ignacion_pedidos.nro_plan, as ignacion_pedidos.nro_orden_fabricacion, as ignacion_pedidos.nro_tarea) a ON Tareas_cabecera.nro_orden_fabricacion = a.nro_orden_fabricacion AND Tareas_cabecer;;
